using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedAt)
                .Select(s => new
                {
                    s.Id,
                    s.TrackingNumber,
                    s.Origin,
                    s.Destination,
                    Status = s.Status.ToString(),
                    s.CreatedAt,
                    s.EstimatedDelivery,
                    s.CustomerEmail,
                    s.Description
                })
                .ToListAsync();

            return Results.Ok(shipments);
        });

        group.MapPost("/", async (CreateShipmentRequest request, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}",
                Origin = request.Origin,
                Destination = request.Destination,
                Status = ShipmentStatus.Pending,
                CreatedAt = DateTime.UtcNow,
                EstimatedDelivery = request.EstimatedDelivery,
                CustomerEmail = request.CustomerEmail,
                Description = request.Description
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();

            return Results.Created($"/api/shipments/{shipment.Id}", new
            {
                shipment.Id,
                shipment.TrackingNumber,
                shipment.Origin,
                shipment.Destination,
                Status = shipment.Status.ToString(),
                shipment.CreatedAt,
                shipment.EstimatedDelivery,
                shipment.CustomerEmail,
                shipment.Description
            });
        });

        group.MapPut("/{id:int}/status", async (int id, UpdateStatusRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            if (!Enum.TryParse<ShipmentStatus>(request.Status, out var status))
                return Results.BadRequest("Invalid status");

            shipment.Status = status;
            if (request.EstimatedDelivery.HasValue)
                shipment.EstimatedDelivery = request.EstimatedDelivery;

            await db.SaveChangesAsync();
            return Results.Ok();
        });

        // Public tracking endpoint - no auth required
        app.MapGet("/api/shipments/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            if (shipment is null)
                return Results.Ok(new { Found = false, Message = "No shipment found with that tracking number." });

            return Results.Ok(new
            {
                Found = true,
                Shipment = new
                {
                    shipment.TrackingNumber,
                    shipment.Origin,
                    shipment.Destination,
                    Status = shipment.Status.ToString(),
                    shipment.CreatedAt,
                    shipment.EstimatedDelivery,
                    shipment.Description
                },
                Message = ""
            });
        });
    }
}

public record CreateShipmentRequest(
    string Origin,
    string Destination,
    DateTime? EstimatedDelivery,
    string CustomerEmail,
    string Description);

public record UpdateStatusRequest(string Status, DateTime? EstimatedDelivery);

