@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveAuto
@inject ShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Shipment Dashboard</h2>

<div class="mb-3">
    <button class="btn btn-primary" @onclick="ShowCreateForm">
        @(_showCreate ? "Cancel" : "➕ New Shipment")
    </button>
    <button class="btn btn-outline-secondary ms-2" @onclick="LoadShipments">🔄 Refresh</button>
</div>

@if (_showCreate)
{
    <div class="card mb-4 p-3">
        <h5>Create Shipment</h5>
        <div class="row g-2">
            <div class="col-md-4">
                <label class="form-label">Origin</label>
                <input class="form-control" @bind="_newShipment.Origin" placeholder="City, Country" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Destination</label>
                <input class="form-control" @bind="_newShipment.Destination" placeholder="City, Country" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Customer Email</label>
                <input class="form-control" type="email" @bind="_newShipment.CustomerEmail" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Description</label>
                <input class="form-control" @bind="_newShipment.Description" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Estimated Delivery</label>
                <input class="form-control" type="date" @bind="_newShipment.EstimatedDelivery" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <button class="btn btn-success" @onclick="CreateShipment">Create</button>
            </div>
        </div>
    </div>
}

@if (_loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (_shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input class="form-control" placeholder="Filter by destination or tracking #..."
               @bind="_filter" @bind:event="oninput" />
    </div>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>
                            <span class="badge @GetStatusBadge(s.Status)">@s.Status</span>
                        </td>
                        <td>@s.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                        <td>
                            <select class="form-select form-select-sm d-inline-block w-auto"
                                    @onchange="e => UpdateStatus(s, e.Value?.ToString())">
                                <option value="">Change status...</option>
                                @foreach (var status in _statuses)
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(_message))
{
    <div class="alert alert-info mt-3">@_message</div>
}

@code {
    private List<ShipmentDto> _shipments = [];
    private bool _loading = true;
    private bool _showCreate;
    private string _filter = "";
    private string _message = "";
    private ShipmentDto _newShipment = new() { EstimatedDelivery = DateTime.Today.AddDays(7) };

    private readonly string[] _statuses = ["Pending", "PickedUp", "InTransit", "OutForDelivery", "Delivered", "Delayed"];

    private IEnumerable<ShipmentDto> FilteredShipments => string.IsNullOrWhiteSpace(_filter)
        ? _shipments
        : _shipments.Where(s =>
            s.Destination.Contains(_filter, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(_filter, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync() => await LoadShipments();

    private async Task LoadShipments()
    {
        _loading = true;
        _shipments = await ShipmentService.GetShipmentsAsync();
        _loading = false;
    }

    private void ShowCreateForm() => _showCreate = !_showCreate;

    private async Task CreateShipment()
    {
        var result = await ShipmentService.CreateShipmentAsync(_newShipment);
        if (result is not null)
        {
            _message = $"Created shipment {result.TrackingNumber}";
            _newShipment = new() { EstimatedDelivery = DateTime.Today.AddDays(7) };
            _showCreate = false;
            await LoadShipments();
        }
        else
        {
            _message = "Failed to create shipment.";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, string? newStatus)
    {
        if (string.IsNullOrEmpty(newStatus)) return;
        var success = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus, shipment.EstimatedDelivery);
        if (success)
        {
            shipment.Status = newStatus;
            _message = $"Updated {shipment.TrackingNumber} to {newStatus}";
        }
    }

    private static string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@rendermode InteractiveAuto
@inject ShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g. TRK-20260101-10001)"
                   @bind="_trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@_searching">
                @(_searching ? "Searching..." : "🔍 Track")
            </button>
        </div>
    </div>
</div>

@if (_result is not null)
{
    @if (_result.Found && _result.Shipment is not null)
    {
        var s = _result.Shipment;
        <div class="card">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>@s.TrackingNumber</strong>
                <span class="badge @GetStatusBadge(s.Status) fs-6">@s.Status</span>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <p><strong>From:</strong> @s.Origin</p>
                        <p><strong>To:</strong> @s.Destination</p>
                        <p><strong>Description:</strong> @s.Description</p>
                    </div>
                    <div class="col-md-6">
                        <p><strong>Shipped:</strong> @s.CreatedAt.ToString("yyyy-MM-dd")</p>
                        <p><strong>Estimated Delivery:</strong>
                            @if (s.EstimatedDelivery.HasValue)
                            {
                                <span class="fw-bold text-primary">@s.EstimatedDelivery.Value.ToString("yyyy-MM-dd")</span>
                            }
                            else
                            {
                                <span class="text-muted">Not available</span>
                            }
                        </p>
                    </div>
                </div>

                <!-- Progress visualization -->
                <div class="mt-3">
                    <h6>Shipment Progress</h6>
                    @{ var progress = GetProgress(s.Status); }
                    <div class="progress" style="height: 25px;">
                        <div class="progress-bar @GetProgressBarClass(s.Status)"
                             role="progressbar"
                             style="width: @(progress)%"
                             aria-valuenow="@progress"
                             aria-valuemin="0"
                             aria-valuemax="100">
                            @s.Status
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning">
            <strong>Not Found:</strong> @_result.Message
        </div>
    }
}

@code {
    private string _trackingNumber = "";
    private TrackingResult? _result;
    private bool _searching;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(_trackingNumber)) return;
        _searching = true;
        _result = await ShipmentService.TrackShipmentAsync(_trackingNumber.Trim());
        _searching = false;
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static int GetProgress(string status) => status switch
    {
        "Pending" => 10,
        "PickedUp" => 30,
        "InTransit" => 55,
        "OutForDelivery" => 80,
        "Delivered" => 100,
        "Delayed" => 55,
        _ => 0
    };

    private static string GetProgressBarClass(string status) => status switch
    {
        "Delivered" => "bg-success",
        "Delayed" => "bg-danger",
        _ => "bg-primary"
    };

    private static string GetStatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService(HttpClient http)
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments") ?? [];
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", new
        {
            shipment.Origin,
            shipment.Destination,
            shipment.EstimatedDelivery,
            shipment.CustomerEmail,
            shipment.Description
        });
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<ShipmentDto>();
        return null;
    }

    public async Task<bool> UpdateStatusAsync(int id, string status, DateTime? estimatedDelivery)
    {
        var response = await http.PutAsJsonAsync($"/api/shipments/{id}/status", new
        {
            Status = status,
            EstimatedDelivery = estimatedDelivery
        });
        return response.IsSuccessStatusCode;
    }

    public async Task<TrackingResult> TrackShipmentAsync(string trackingNumber)
    {
        return await http.GetFromJsonAsync<TrackingResult>($"/api/shipments/track/{trackingNumber}")
            ?? new TrackingResult { Found = false, Message = "Unable to reach tracking service." };
    }
}

