using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService(HttpClient http)
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("/api/shipments") ?? [];
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await http.PostAsJsonAsync("/api/shipments", new
        {
            shipment.Origin,
            shipment.Destination,
            shipment.EstimatedDelivery,
            shipment.CustomerEmail,
            shipment.Description
        });
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<ShipmentDto>();
        return null;
    }

    public async Task<bool> UpdateStatusAsync(int id, string status, DateTime? estimatedDelivery)
    {
        var response = await http.PutAsJsonAsync($"/api/shipments/{id}/status", new
        {
            Status = status,
            EstimatedDelivery = estimatedDelivery
        });
        return response.IsSuccessStatusCode;
    }

    public async Task<TrackingResult> TrackShipmentAsync(string trackingNumber)
    {
        return await http.GetFromJsonAsync<TrackingResult>($"/api/shipments/track/{trackingNumber}")
            ?? new TrackingResult { Found = false, Message = "Unable to reach tracking service." };
    }
}

